"""matplotlib.bezier — Bezier curve utilities."""

import numpy as _np


def get_intersection(cx1, cy1, cos_t1, sin_t1, cx2, cy2, cos_t2, sin_t2):
    return (0.0, 0.0)


def get_normal_points(cx, cy, cos_t, sin_t, length):
    return ((cx - sin_t * length, cy + cos_t * length),
            (cx + sin_t * length, cy - cos_t * length))


def split_bezier_intersecting_with_closedpath(bezier, inside_closedpath, tolerance=0.01):
    return bezier[:len(bezier)//2], bezier[len(bezier)//2:]


def find_bezier_t_intersecting_with_closedpath(bezier_point_at_t, inside_closedpath,
                                                t0=0., t1=1., tolerance=0.01):
    return (t0 + t1) / 2


class BezierSegment:
    def __init__(self, control_points):
        self._cpoints = _np.asarray(control_points)

    def point_at_t(self, t):
        n = len(self._cpoints) - 1
        result = _np.zeros(2)
        for i, cp in enumerate(self._cpoints):
            b = _comb(n, i) * (1 - t)**(n - i) * t**i
            result += b * cp
        return tuple(result)

    @property
    def control_points(self):
        return self._cpoints


def _comb(n, k):
    from math import factorial
    return factorial(n) // (factorial(k) * factorial(n - k))


def make_wedge_fly(x, y, w, h, theta1, theta2, n=50):
    return _np.zeros((n, 2))
